// file-demo.js
import { readFile, writeFile } from 'fs/promises';

async function main() {
  // Read a file asynchronously — non-blocking
  const content = await readFile('input.txt', 'utf8');
  console.log('Read:', content.slice(0, 50));

  // Transform the content
  const upper = content.toUpperCase();

  // Write the result
  await writeFile('output.txt', upper, 'utf8');
  console.log('Written output.txt');
}

main().catch(console.error);

// server.js — run with: node server.js
import { createServer } from 'http';

const PORT = process.env.PORT ?? 3000;

const server = createServer((req, res) => {
  const url = new URL(req.url, `http://localhost:${PORT}`);

  if (req.method === 'GET' && url.pathname === '/health') {
    res.writeHead(200, { 'Content-Type': 'application/json' });
    res.end(JSON.stringify({ status: 'ok', uptime: process.uptime() }));
    return;
  }

  if (req.method === 'GET' && url.pathname === '/') {
    res.writeHead(200, { 'Content-Type': 'text/plain' });
    res.end('Hello from Node.js!');
    return;
  }

  res.writeHead(404, { 'Content-Type': 'text/plain' });
  res.end('Not Found');
});

server.listen(PORT, () => {
  console.log(`Server listening on http://localhost:${PORT}`);
});

// routes/users.js — Express route handlers
import express from 'express';
import { db } from '../db/client.js';   // hypothetical database client

const router = express.Router();

// GET /users — list all users (paginated)
router.get('/', async (req, res, next) => {
  try {
    const page  = Math.max(1, parseInt(req.query.page)  || 1);
    const limit = Math.min(100, parseInt(req.query.limit) || 20);
    const offset = (page - 1) * limit;

    const [rows, [{ total }]] = await Promise.all([
      db.query('SELECT id, name, email FROM users LIMIT ? OFFSET ?', [limit, offset]),
      db.query('SELECT COUNT(*) AS total FROM users'),
    ]);

    res.json({
      data: rows,
      meta: { page, limit, total: Number(total), pages: Math.ceil(total / limit) },
    });
  } catch (err) {
    next(err); // passes to the error handler middleware
  }
});

// GET /users/:id — single user
router.get('/:id', async (req, res, next) => {
  try {
    const [user] = await db.query(
      'SELECT id, name, email, created_at FROM users WHERE id = ?',
      [req.params.id]
    );

    if (!user) {
      return res.status(404).json({ error: 'User not found' });
    }

    res.json({ data: user });
  } catch (err) {
    next(err);
  }
});

export default router;

// app.js — application entry point
import express from 'express';
import usersRouter from './routes/users.js';

const app = express();
app.use(express.json());

app.use('/users', usersRouter);

// Centralized error handler — catches anything passed to next(err)
app.use((err, req, res, next) => {
  console.error(err);
  res.status(err.status ?? 500).json({ error: err.message ?? 'Internal Server Error' });
});

const PORT = process.env.PORT ?? 3000;
app.listen(PORT, () => console.log(`API running on port ${PORT}`));

import { readFileSync } from 'fs';

// ❌ readFileSync blocks the event loop — no other requests are handled until this returns
app.get('/config', (req, res) => {
  const config = readFileSync('./config.json', 'utf8'); // blocks the entire server
  res.json(JSON.parse(config));
});

// ✅ Use the async version
import { readFile } from 'fs/promises';

app.get('/config', async (req, res, next) => {
  try {
    const config = await readFile('./config.json', 'utf8'); // non-blocking
    res.json(JSON.parse(config));
  } catch (err) {
    next(err);
  }
});

