// ✅ Always handle errors: await in a try/catch or attach .catch()
async function fetchData() {
  try {
    return await db.query('SELECT ...');
  } catch (err) {
    logger.error('DB query failed:', err);
    throw err; // re-throw so the caller knows it failed
