import cluster from 'cluster';
import os from 'os';
import { createServer } from 'http';

if (cluster.isPrimary) {
  const numCPUs = os.cpus().length;
  console.log(`Primary ${process.pid}: forking ${numCPUs} workers`);
  for (let i = 0; i < numCPUs; i++) {
    cluster.fork();
  }
  cluster.on('exit', (worker) => {
    console.log(`Worker ${worker.process.pid} died — restarting`);
    cluster.fork();
  });
} else {
  // Each worker runs this block
  createServer((req, res) => {
    res.end(`Hello from worker ${process.pid}`);
  }).listen(3000);
}

import { createReadStream } from 'fs';
import { createGunzip } from 'zlib';
import { pipeline } from 'stream/promises';

// Stream a .gz file decompressed to the HTTP response
app.get('/data', async (req, res, next) => {
  try {
    res.setHeader('Content-Type', 'application/json');
    await pipeline(
      createReadStream('./data.json.gz'),
      createGunzip(),
      res
    );
  } catch (err) {
    next(err);
  }
});

import { Worker } from 'worker_threads';

// Offload heavy computation to a dedicated thread
function runComputation(data) {
  return new Promise((resolve, reject) => {
    const worker = new Worker('./compute-worker.js', { workerData: data });
    worker.on('message', resolve);
    worker.on('error', reject);
  });
}

app.post('/process', async (req, res, next) => {
  try {
    const result = await runComputation(req.body);
    res.json({ result });
  } catch (err) {
    next(err);
  }
});

import { z } from 'zod';

const CreateUserSchema = z.object({
  name:  z.string().min(1).max(100),
  email: z.string().email(),
  age:   z.number().int().min(0).max(120).optional(),
});

app.post('/users', async (req, res, next) => {
  const parsed = CreateUserSchema.safeParse(req.body);
  if (!parsed.success) {
    return res.status(400).json({ error: parsed.error.flatten() });
  }
  const user = await db.createUser(parsed.data); // safe, validated data only
  res.status(201).json({ data: user });
});

import helmet from 'helmet';
import rateLimit from 'express-rate-limit';

app.use(helmet());   // set secure HTTP headers

app.use(rateLimit({
  windowMs: 15 * 60 * 1000, // 15 minutes
  limit: 100,               // max 100 requests per window per IP
  standardHeaders: true,
  legacyHeaders: false,
}));
